checker_dsl:
EXISTS (`expression E`) {
  AND {
    OR {
      EXISTS (`binary expression B`) {
        AND {
          (`B = E`),
          EXISTS (`expression L`) {
            (`L is the left operand of B`)
          },
          EXISTS (`expression R`) {
            (`R is the right operand of B`)
          }
        }
      },
      EXISTS (`casting expression C`) {
        AND {
          (`C = E`),
          EXISTS (`expression I`) {
            (`I is the inner expression of C`)
          }
        }
      },
      EXISTS (`multiplication expression M`) {
        AND {
          (`M = E`),
          EXISTS (`expression O`) {
            AND {
              (`O is an operand of M`),
              (`O is a CompileTimeConstantExpr`),
              (`O evaluates to integer value 0`)
            }
          }
        }
      },
      EXISTS (`remainder expression R`) {
        AND {
          (`R = E`),
          (`left operand of R has integral type`),
          EXISTS (`expression RO`) {
            AND {
              (`RO is the right operand of R`),
              (`RO is a CompileTimeConstantExpr`),
              (`RO evaluates to integer value 1`)
            }
          }
        }
      },
      EXISTS (`bitwise AND expression A`) {
        AND {
          (`A = E`),
          EXISTS (`expression AO`) {
            AND {
              (`AO is an operand of A`),
              (`AO is a CompileTimeConstantExpr`),
              (`AO evaluates to integer value 0`)
            }
          }
        }
      },
      EXISTS (`logical AND expression LA`) {
        AND {
          (`LA = E`),
          EXISTS (`expression LAO`) {
            AND {
              (`LAO is an operand of LA`),
              (`LAO is a BooleanLiteral`),
              (`LAO has boolean value false`)
            }
          }
        }
      },
      EXISTS (`logical OR expression LO`) {
        AND {
          (`LO = E`),
          EXISTS (`expression LOO`) {
            AND {
              (`LOO is an operand of LO`),
              (`LOO is a BooleanLiteral`),
              (`LOO has boolean value true`)
            }
          }
        }
      }
    },
    NOT {
      EXISTS (`type access TA`) {
        AND {
          (`TA = E`),
          (`type of TA is ErrorType`)
        }
      }
    },
    EXISTS (`expression CHILD`) {
      AND {
        (`CHILD is a child expression of E`),
        NOT {
          OR {
            (`CHILD is a Literal or TypeAccess or ArrayTypeAccess or WildcardTypeAccess`),
            EXISTS (`binary expression B`) {
              AND {
                (`B = CHILD`),
                EXISTS (`expression L`) {
                  (`L is the left operand of B`)
                },
                EXISTS (`expression R`) {
                  (`R is the right operand of B`)
                }
              }
            },
            EXISTS (`casting expression C`) {
              AND {
                (`C = CHILD`),
                EXISTS (`expression I`) {
                  (`I is the inner expression of C`)
                }
              }
            },
            EXISTS (`multiplication expression M`) {
              AND {
                (`M = CHILD`),
                EXISTS (`expression O`) {
                  AND {
                    (`O is an operand of M`),
                    (`O is a CompileTimeConstantExpr`),
                    (`O evaluates to integer value 0`)
                  }
                }
              }
            },
            EXISTS (`remainder expression R`) {
              AND {
                (`R = CHILD`),
                (`left operand of R has integral type`),
                EXISTS (`expression RO`) {
                  AND {
                    (`RO is the right operand of R`),
                    (`RO is a CompileTimeConstantExpr`),
                    (`RO evaluates to integer value 1`)
                  }
                }
              }
            },
            EXISTS (`bitwise AND expression A`) {
              AND {
                (`A = CHILD`),
                EXISTS (`expression AO`) {
                  AND {
                    (`AO is an operand of A`),
                    (`AO is a CompileTimeConstantExpr`),
                    (`AO evaluates to integer value 0`)
                  }
                }
              }
            },
            EXISTS (`logical AND expression LA`) {
              AND {
                (`LA = CHILD`),
                EXISTS (`expression LAO`) {
                  AND {
                    (`LAO is an operand of LA`),
                    (`LAO is a BooleanLiteral`),
                    (`LAO has boolean value false`)
                  }
                }
              }
            },
            EXISTS (`logical OR expression LO`) {
              AND {
                (`LO = CHILD`),
                EXISTS (`expression LOO`) {
                  AND {
                    (`LOO is an operand of LO`),
                    (`LOO is a BooleanLiteral`),
                    (`LOO has boolean value true`)
                  }
                }
              }
            }
          }
        },
        NOT { (`CHILD is an Annotation`) }
      }
    },
    NOT { (`E is a CompileTimeConstantExpr`) },
    NOT {
      EXISTS (`multiplication expression ME`) {
        AND {
          (`ME = E`),
          EXISTS (`expression O`) {
            AND {
              (`O is an operand of ME`),
              (`O is an IntegerLiteral`),
              (`O evaluates to integer value 0`)
            }
          }
        }
      }
    },
    NOT {
      EXISTS (`logical AND expression LAE`) {
        AND {
          (`LAE = E`),
          EXISTS (`expression O`) {
            AND {
              (`O is an operand of LAE`),
              (`O is a BooleanLiteral`),
              (`O has boolean value false`)
            }
          }
        }
      }
    },
    NOT {
      EXISTS (`constructor CON`) {
        AND {
          (`CON encloses E`),
          EXISTS (`type T`) {
            AND {
              (`T is the type of the last parameter of CON`),
              (`T is a RefType`),
              (`T has qualified name "kotlinx.serialization.internal.SerializationConstructorMarker"`)
            }
          }
        }
      }
    }
  }
}
